import microcoapy
import machine

# Define CoAP server resources
resources = {
    "/sensors/temp": 0,
    "/actuators/light": 1,
}

# CoAP server handler
class CoapServer(microcoapy.Server):
    def do_get(self, path):
        if path in resources:
            value = resources[path]
            return microcoapy.Message.response(
                microcoapy.Code.CONTENT,
                value.encode(),
            )
        return microcoapy.Message.response(microcoapy.Code.NOT_FOUND)

    def do_put(self, path, data):
        if path in resources:
            resources[path] = int(data.decode())
            return microcoapy.Message.response(microcoapy.Code.CHANGED)
        return microcoapy.Message.response(microcoapy.Code.NOT_FOUND)

# Create CoAP server object
server = CoapServer()

# Start CoAP server
server.listen()

# Main loop
while True:
    server.poll()